def solution(limit: int = 28123) -> int:
    """
    Optimized version using a set for O(1) lookups and a more concise divisor sum sieve.
    """
    # Divisor sum sieve
    div_sum = [1] * (limit + 1)
    for i in range(2, int(limit**0.5) + 1):
        div_sum[i*i] += i
        for j in range(i + 1, limit // i + 1):
            div_sum[i*j] += i + j

    abundants = [i for i, s in enumerate(div_sum) if i > 1 and s > i]
    abundant_set = set(abundants)

    def is_abundant_sum(n):
        for a in abundants:
            if a > n // 2: break
            if (n - a) in abundant_set:
                return True
        return False

    return sum(n for n in range(1, limit + 1) if not is_abundant_sum(n))


